            // ─────────────────────────────────────────────
            // 5. COMPREHENSIVE ERROR CATALOGUE
            // ─────────────────────────────────────────────
            errorCatalogue: {
                overview: "Every significant error pattern across all tiers, with corrections",

                tier1Errors: [
                    {
                        error: "Applying operation to only part of a side",
                        example: "From 3x + 6 = y: writing x + 6 = y/3",
                        correction: "Subtract 6 first: 3x = y − 6; then x = (y−6)/3"
                    },
                    {
                        error: "Wrong sign when moving a term",
                        example: "x − 5 = y → x = y − 5",
                        correction: "Add 5 to both sides: x = y + 5"
                    },
                    {
                        error: "Stopping at −x = k",
                        example: "−x = 7 → writing x = 7",
                        correction: "Multiply by −1: x = −7"
                    }
                ],

                tier2Errors: [
                    {
                        error: "Cross-multiplying when one side is not a single fraction",
                        example: "x/2 + 3 = y → xy = 6",
                        correction: "Clear all terms: multiply every term by 2: x + 6 = 2y → x = 2y − 6"
                    },
                    {
                        error: "Forgetting to multiply non-fraction terms by the LCM",
                        example: "x/3 + 5 = y, multiply by 3: x + 5 = 3y (correct, 5 IS multiplied)",
                        correction: "Always apply LCM to EVERY term including non-fraction terms"
                    },
                    {
                        error: "Adding reciprocals like regular fractions",
                        example: "1/R = 1/2 + 1/3 → R = 2 + 3 = 5",
                        correction: "1/R = 5/6 → R = 6/5"
                    }
                ],

                tier3Errors: [
                    {
                        error: "Forgetting ± when taking even roots",
                        example: "x² = 25 → x = 5 only",
                        correction: "x = ±5 (or x = 5 if physical context requires positive only)"
                    },
                    {
                        error: "Squaring before isolating the root",
                        example: "√x + 3 = 7: squaring gives x + 9 = 49",
                        correction: "Isolate first: √x = 4; then square: x = 16"
                    },
                    {
                        error: "Squaring a sum incorrectly",
                        example: "(a + b)² = a² + b²",
                        correction: "(a + b)² = a² + 2ab + b²"
                    },
                    {
                        error: "Including ± for cube root",
                        example: "x³ = 8 → x = ±2",
                        correction: "Cube root is unique: x = 2 only"
                    }
                ],

                tier4Errors: [
                    {
                        error: "Factorising incorrectly",
                        example: "ax + bx = x · (a · b) = abx",
                        correction: "ax + bx = x(a + b)"
                    },
                    {
                        error: "Attempting collect-factorise when x appears non-linearly",
                        example: "y = x² + x, treating as y = x(x + 1) → x = y/(x+1) — circular",
                        correction: "Use quadratic formula or completing the square"
                    },
                    {
                        error: "Forgetting a term when expanding",
                        example: "a(x + b) = ax + b",
                        correction: "a(x + b) = ax + ab"
                    }
                ],

                tier5Errors: [
                    {
                        error: "Squaring before clearing the fraction",
                        example: "y = a/√x: squaring immediately gives y² = a²/x, which is actually correct here, but for y = (a + √x)/b squaring too early creates mess",
                        correction: "Clear fractions first, then isolate the root, then square"
                    },
                    {
                        error: "Forgetting to square the entire bracket",
                        example: "T/(2π) = √(L/g): squaring to T/4π² = L/g",
                        correction: "(T/(2π))² = T²/(4π²) = L/g"
                    }
                ],

                tier6Errors: [
                    {
                        error: "sin⁻¹(x) interpreted as 1/sin(x)",
                        example: "sin⁻¹(0.5) = 1/sin(0.5) ≈ 2.09",
                        correction: "sin⁻¹(0.5) = arcsin(0.5) = 30° = π/6"
                    },
                    {
                        error: "log(a + b) = log(a) + log(b)",
                        example: "log(3 + 4) = log(3) + log(4)",
                        correction: "log(3 × 4) = log(3) + log(4); log(a+b) has no simplification"
                    },
                    {
                        error: "Taking log before isolating the exponential",
                        example: "3eˣ + 5 = 20: taking ln of 3eˣ as ln(3) + x",
                        correction: "Subtract 5: 3eˣ = 15; divide by 3: eˣ = 5; take ln: x = ln(5)"
                    },
                    {
                        error: "Not restricting domain when finding inverse of a non-injective function",
                        example: "f(x) = x² has no unique inverse over all reals",
                        correction: "Restrict to x ≥ 0: f⁻¹(x) = √x"
                    }
                ]
            },

