                    derivation: "→OM = →OA + (1/2)→AB = →OA + (1/2)(→OB - →OA) = (1/2)(→OA + →OB)",
                    example: "If →OA = (2; 4) and →OB = (6; 2), midpoint M has position vector (4; 3)"
